import { describe, expect, it } from 'vitest';
import { COUPONS, findCoupon, getCouponExpiryInfo } from './coupons';

describe('coupons expiry behavior', () => {
  it('returns null for expired coupons', () => {
    const expiredCoupon = {
      ...COUPONS.DESCUENTO10,
      code: 'EXPIRADO_TEST',
      expiresAt: '2020-01-01T00:00:00.000Z',
    };

    const info = getCouponExpiryInfo(expiredCoupon, new Date('2026-04-29T12:00:00.000Z'));
    expect(info.isExpired).toBe(true);

    expect(findCoupon('DESCUENTO10')).not.toBeNull();
  });

  it('marks coupon as expiring soon when remaining days are 3 or less', () => {
    const soonInfo = getCouponExpiryInfo(
      { ...COUPONS.DESCUENTO10, expiresAt: '2026-05-02T23:59:59.000Z' },
      new Date('2026-04-30T10:00:00.000Z')
    );

    expect(soonInfo.isExpired).toBe(false);
    expect(soonInfo.isExpiringSoon).toBe(true);
    expect(soonInfo.daysRemaining).toBeLessThanOrEqual(3);
  });
});
